"use strict";parserFactory.register("woopread.com",()=>new WoopreadParser);class WoopreadParser extends Parser{constructor(){super()}extractTitleImpl(e){return e.querySelector("h1.text-3xl")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.relative .text-text-secondary")]}extractAuthor(e){let r=e.querySelector("div.mb-4:nth-of-type(4) a");return null===r?super.extractAuthor(e):r.textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.relative")}async getChapterUrls(e){const r=[...e.querySelectorAll("main.grow .notranslate .mt-8 .grid-cols-1 a")],t=[...e.querySelectorAll("main.grow .line-clamp-2")];let l=[];for(let e=0;e<r.length;e++)l.push({sourceUrl:r[e].href,title:t[e].textContent});return l.reverse()}findChapterTitle(e){return e.querySelector("h2.text-2xl")}findContent(e){return e.querySelector("div[id^='chapter']")}}